#include <stdlib.h>
#include <time.h>

int main(void) {
    int numbers[5], position, score = 0;
    char guess;
    srand(time(NULL));

    for (int i = 0; i < 5; i++) numbers[i] = rand() % 10 + 1;

    printf("Numbers: ");
    for (int i = 0; i < 5; i++) {
        if (i > 0) printf(" ");
        printf("%d", numbers[i]);
    }
    printf("\nPick ");

    if (scanf("%d %c", &position, &guess) == 2) {
        position--; // Convert to zero-based index
        if (position >= 0 && position < 5) {
            int isEven = numbers[position] % 2 == 0;
            char correctGuess = isEven ? 'E' : 'O';
            if (guess == correctGuess) score += 10;
        }
    }

    printf("win %d points\n", score);
    return 0;
}
